import{_ as e,o as r,c as i,ah as h}from"./chunks/framework.C2p4DT9L.js";const b=JSON.parse('{"title":"性能优化","description":"","frontmatter":{"title":"性能优化","order":9},"headers":[],"relativePath":"server/distribute/qos/performance/index.md","filePath":"server/distribute/qos/performance/index.md"}'),l={name:"server/distribute/qos/performance/index.md"};function t(n,a,d,o,s,p){return r(),i("div",null,[...a[0]||(a[0]=[h('<h1 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h1><p>性能优化是服务端开发的核心能力，通过减少延迟、增加吞吐、降低资源消耗，提升用户体验和系统容量。</p><h2 id="性能指标" tabindex="-1">性能指标 <a class="header-anchor" href="#性能指标" aria-label="Permalink to “性能指标”">​</a></h2><h3 id="吞吐量" tabindex="-1">吞吐量 <a class="header-anchor" href="#吞吐量" aria-label="Permalink to “吞吐量”">​</a></h3><p>吞吐量是单位时间处理的请求数，常用 QPS 或 RPS 表示。</p><h3 id="延迟" tabindex="-1">延迟 <a class="header-anchor" href="#延迟" aria-label="Permalink to “延迟”">​</a></h3><p>延迟是请求的处理时间，常用 P50、P95、P99 表示。</p><h3 id="资源使用率" tabindex="-1">资源使用率 <a class="header-anchor" href="#资源使用率" aria-label="Permalink to “资源使用率”">​</a></h3><p>CPU、内存、磁盘、网络的使用百分比。</p><h2 id="性能分析" tabindex="-1">性能分析 <a class="header-anchor" href="#性能分析" aria-label="Permalink to “性能分析”">​</a></h2><h3 id="cpu-分析" tabindex="-1">CPU 分析 <a class="header-anchor" href="#cpu-分析" aria-label="Permalink to “CPU 分析”">​</a></h3><p>工具：top、htop、perf、火焰图。</p><p>瓶颈：算法复杂度、不必要的计算、锁竞争。</p><h3 id="内存分析" tabindex="-1">内存分析 <a class="header-anchor" href="#内存分析" aria-label="Permalink to “内存分析”">​</a></h3><p>工具：free、valgrind、pprof。</p><p>瓶颈：内存泄漏、缓存过大、对象过多。</p><h3 id="i-o-分析" tabindex="-1">I/O 分析 <a class="header-anchor" href="#i-o-分析" aria-label="Permalink to “I/O 分析”">​</a></h3><p>工具：iostat、iftop、strace。</p><p>瓶颈：磁盘慢、网络慢、系统调用过多。</p><h3 id="锁分析" tabindex="-1">锁分析 <a class="header-anchor" href="#锁分析" aria-label="Permalink to “锁分析”">​</a></h3><p>工具：perf lock、pstack、JStack。</p><p>瓶颈：锁粒度大、锁持有时间长、热点锁。</p><h2 id="性能优化策略" tabindex="-1">性能优化策略 <a class="header-anchor" href="#性能优化策略" aria-label="Permalink to “性能优化策略”">​</a></h2><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to “缓存”">​</a></h3><p>内存缓存（Redis）、本地缓存（Caffeine）、CDN 缓存、浏览器缓存。</p><h3 id="批处理" tabindex="-1">批处理 <a class="header-anchor" href="#批处理" aria-label="Permalink to “批处理”">​</a></h3><p>批量插入、批量查询、批量更新。</p><h3 id="异步处理" tabindex="-1">异步处理 <a class="header-anchor" href="#异步处理" aria-label="Permalink to “异步处理”">​</a></h3><p>消息队列、后台任务、事件驱动。</p><h3 id="连接池" tabindex="-1">连接池 <a class="header-anchor" href="#连接池" aria-label="Permalink to “连接池”">​</a></h3><p>数据库连接池、HTTP 连接池、Redis 连接池。</p><h2 id="性能测试" tabindex="-1">性能测试 <a class="header-anchor" href="#性能测试" aria-label="Permalink to “性能测试”">​</a></h2><h3 id="压测" tabindex="-1">压测 <a class="header-anchor" href="#压测" aria-label="Permalink to “压测”">​</a></h3><p>压测工具：ab、wrk、JMeter、Locust。</p><p>压测指标：QPS、延迟、错误率、资源使用率。</p><h3 id="基准测试" tabindex="-1">基准测试 <a class="header-anchor" href="#基准测试" aria-label="Permalink to “基准测试”">​</a></h3><p>基准测试工具：Go benchmark、JMH、pytest-benchmark。</p><p>注意事项：预热、多次运行、环境一致、统计显著性。</p>',38)])])}const f=e(l,[["render",t]]);export{b as __pageData,f as default};
